    content: /* @__PURE__ */ jsxRuntimeExports.jsx(jsxRuntimeExports.Fragment, { children: /* @__PURE__ */ jsxRuntimeExports.jsx("p", { children: "If you opt-in to receive text messages from Tele-Blast for multi-factor authentication (MFA), any opt-in data is not shared or sold to third parties or affiliates for marketing purposes. Messages will only come from Tele-Blast. MFA message frequency will vary and message and data rates may apply. Replying to an MFA message with STOP will disable MFA text messages." }) })
